import osimport matplotlib.pyplot as pltimport pandas as pdfrom config.paths import CHARTS_PATHdef save_bar_chart(series,title,filename,xlabel='',ylabel='Count'):    plt.figure(figsize = (10,10))    plt.bar(series.value_counts().index,series.value_counts().values)    plt.title(title)    plt.xlabel(xlabel)    plt.ylabel(ylabel)    plt.tight_layout()    plt.savefig(os.path.join(CHARTS_PATH,filename))    plt.close()def save_histogram(series, title, filename,bins=20):    plt.figure(figsize=(10, 10))    plt.hist(series,bins=bins)    plt.title(title)    plt.xlabel(series.name)    plt.ylabel('Frequency')    plt.tight_layout()    plt.savefig(os.path.join(CHARTS_PATH,filename))    plt.close()def save_stacked_bar(crosstab, title, filename):    plt.figure(figsize=(10, 10))    crosstab.plot(kind='bar',stacked=True)    plt.title(title)    plt.tight_layout()    plt.savefig(os.path.join(CHARTS_PATH,filename))    plt.close()def create_visuals(data:pd.DataFrame):    save_bar_chart(data['Attrition'],                   'Attrition Distribution',                   'Attrition_distribution.png')    save_histogram(data['Age'],                   title = 'Age Distribution',                   filename = 'age_distribution.png')    save_stacked_bar(pd.crosstab(['OverTime'],data['Attrition']),                     title = 'Overtime Distribution',                     filename = 'overtime_distribution.png')def main():    from src.components.data_ingestion import load_data    data = load_data()    create_visuals(data)if __name__ == '__main__':    main()